import { ComponentModule } from '@/main';
import {
    PAGE_VISIT,
    REFERENCE_CLEAR,
    REFERENCE_FOUND,
    REFERENCE_GET,
    REFERENCE_INIT,
    REFERENCE_NOT_FOUND,
    TOAST_TRIGGER,
} from '@/models/events';
import { Iva } from '@/models/iva';
import { PaginationMetaData } from '@/models/paginacion';
import { Precio } from '@/models/precio';
import { Familia, Marca, ReferenceOrigin, ReferenceOrigins, Referencia } from '@/models/referencia';
import { ToastError } from '@/models/toast';
import { url } from '@/services/api.service';
import { Modal } from 'flowbite';

const MIN_SEARCH_LENGTH = 2;

export default {
    name: () => 'reference',
    template: () => import('./reference.html?raw'),
    data: () => ({
        reference: '',
        origin: null as ReferenceOrigin | null,

        // refer modal búsqueda
        modalSearchRefer: null as Modal | null,

        // datos selects modal búsqueda
        marcas: [] as Marca[],
        familias: [] as Familia[],

        // estados de modal búsqueda
        hasSearched: false,
        loadingReferences: false,

        // referencia seleccionada modal búsqueda
        selectedRefer: null as Referencia | null,

        // filtros modal búsqueda
        currentRefer: '',
        currentDesc: '',
        currentMarca: '',
        currentFamilia: '',

        // resultado referencias modal búsqueda
        referencias: [] as Referencia[],
        paginationMetaData: null as PaginationMetaData | null,

        // paginación modal búsqueda
        currentPage: 1,
        pageInfo: '',

        // ordenación modal búsqueda
        sortColumnKey: '',
        sortOrder: 'asc',

        init() {
            console.log('reference@init');

            this.initModalSearchRefer();

            const watchFields = ['currentRefer', 'currentDesc', 'currentMarca', 'currentFamilia'];
            watchFields.forEach((field) => {
                this.$watch(field, () => {
                    if (!this.hasSearched) {
                        this.hasSearched = true;
                    }
                    if (this.currentPage !== 1) {
                        this.currentPage = 1;
                    }
                    if (
                        this.currentRefer.length < MIN_SEARCH_LENGTH &&
                        this.currentDesc.length < MIN_SEARCH_LENGTH &&
                        this.currentMarca === '' &&
                        this.currentFamilia === ''
                    ) {
                        this.resetValues();
                    }
                });
            });

            this.$nextTick(() => {
                console.log('101-reference@nextTick');

                const parent = this.$refs.form?.closest('[data-origin]') as HTMLElement | null;
                console.log('1-parent', parent);
                console.log('2-origin', parent?.dataset.origin);

                console.log(
                    '3-condicion',
                    // @ts-expect-error 2345
                    parent?.dataset.origin !== undefined && ReferenceOrigins.includes(parent?.dataset.origin),
                );

                // @ts-expect-error 2345
                if (parent?.dataset.origin !== undefined && ReferenceOrigins.includes(parent?.dataset.origin)) {
                    this.origin = parent.dataset.origin as ReferenceOrigin;
                }

                this.$dispatch(REFERENCE_INIT, { origin: this.origin as ReferenceOrigin });
            });

            // @ts-expect-error 2769
            window.addEventListener(REFERENCE_GET, (e: CustomEvent) => {
                console.log('99-reference@get', e.detail);
                console.log('99-origin', this.origin);

                if (e.detail.origin === this.origin) {
                    //console.log('reference@get', e.detail);
                    //console.log('origin' ,this.origin);

                    this.reference = e.detail.refer;
                }
            });

            // @ts-expect-error 2769
            window.addEventListener(REFERENCE_CLEAR, (e: CustomEvent) => {
                console.log('reference@clear', e.detail);
                this.reference = '';
            });

            // @ts-expect-error 2769
            window.addEventListener(REFERENCE_NOT_FOUND, async (e: CustomEvent) => {
                console.log('reference@not-found', e.detail);
                if (e.detail.origin === this.origin) {
                    this.currentRefer = e.detail.reference;
                    this.modalSearchRefer?.show();
                    this.$refs.searchReferInput?.focus();
                    await this.searchRefer();
                }
            });
        },

        initModalSearchRefer() {
            this.modalSearchRefer = new Modal(
                this.$refs.modalSearchRefer,
                {
                    placement: 'center',
                    backdrop: 'static', // Prevent closing the reference search modal when clicking outside
                    backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-40',
                    closable: true,
                    onHide: () => {
                        console.log('modal is hidden');
                        this.resetValues();
                        // Reiniciamos los valores de los campos de búsqueda al cerrar el modal
                        [this.currentRefer, this.currentDesc, this.currentMarca, this.currentFamilia] = [
                            '',
                            '',
                            '',
                            '',
                        ];
                    },
                    onShow: () => {
                        console.log('modal is shown');
                    },
                    onToggle: () => {
                        console.log('modal has been toggled');
                    },
                },
                {
                    id: 'modal-search-refer',
                    override: true,
                },
            );

            document.addEventListener(PAGE_VISIT, () => {
                console.log('reference@page-visit');
                this.modalSearchRefer?.hide();
            });
        },

        async prevPage() {
            if (this.currentPage > 1) {
                this.currentPage--;
                this.selectedRefer = null;
                await this.searchRefer();
            }
        },

        async nextPage() {
            if (this.currentPage < this.paginationMetaData?.totalPages) {
                this.currentPage++;
                this.selectedRefer = null;
                await this.searchRefer();
            }
        },

        async openSearchReferModal() {
            await Promise.all([this.loadMarcas(), this.loadFamilias()]);
            this.modalSearchRefer?.show();
        },

        selectReferencia(reference: Referencia) {
            this.selectedRefer = reference;
        },

        async setFormReference() {
            if (this.selectedRefer !== null) {
                try {
                    const [referenceData, priceAndDiscount, ivas] = await Promise.all([
                        this.getReferenceData(this.selectedRefer.refer),
                        this.getPriceAndDiscount(this.selectedRefer.refer),
                        this.getIvas(this.selectedRefer.refer),
                    ]);

                    if (!referenceData) {
                        throw new Error('Referencia no encontrada');
                    }
                    this.$dispatch(REFERENCE_FOUND, {
                        referenceData,
                        priceAndDiscount,
                        ivas,
                        origin: this.origin as ReferenceOrigin,
                    });
                    this.reference = this.selectedRefer.refer;
                    this.modalSearchRefer?.hide();
                } catch (error: any) {
                    console.log('error', error);
                }
            }
        },

        async searchRefer() {
            const filter = `${this.buildFilter()}&page=${this.currentPage}&pageSize=10&sort=${this.sortColumnKey}&order=${this.sortOrder}`;

            try {
                if (!filter.startsWith('&page')) {
                    this.loadingReferences = true;
                    const r = await fetch(url(`/isiWeb/web/v1/empresas/01/referencias?${filter}`), {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                    });

                    if (!r.ok) {
                        throw new Error('Error al buscar referencias');
                    }
                    const response = await r.json();

                    this.referencias = response.data as Referencia[];
                    this.paginationMetaData = response.meta as PaginationMetaData;

                    const startEntry = (this.currentPage - 1) * 10 + 1;
                    const endEntry = Math.min(this.currentPage * 10, this.paginationMetaData.totalRows);
                    this.pageInfo = `Mostrando ${startEntry} a ${endEntry} de ${this.paginationMetaData.totalRows} registros`;
                    this.loadingReferences = false;
                }
            } catch (error: any) {
                console.log('error', error);
                this.resetValues();
                this.loadingReferences = false;
            }
        },

        async sortReferencias(columnKey: string) {
            this.currentPage = 1;
            this.sortColumnKey = columnKey;
            this.sortOrder = this.sortOrder === 'asc' ? 'desc' : 'asc';
            await this.searchRefer();
        },

        resetValues() {
            this.pageInfo = '';
            this.referencias = [];
            this.paginationMetaData = null;
            this.hasSearched = false;
            this.loadingReferences = false;
            this.selectedRefer = null;
        },

        buildFilter(): string {
            let filter = '';

            if (this.currentRefer.length >= MIN_SEARCH_LENGTH) {
                filter += `refer:like=${this.currentRefer}`;
            }
            if (this.currentDesc.length >= MIN_SEARCH_LENGTH) {
                if (filter !== '') {
                    filter += `&artde1:like=${this.currentDesc}`;
                } else {
                    filter += `artde1:like=${this.currentDesc}`;
                }
            }
            if (this.currentMarca !== '') {
                if (filter !== '') {
                    filter += `&mar:like=${this.currentMarca}`;
                } else {
                    filter += `mar:like=${this.currentMarca}`;
                }
            }
            if (this.currentFamilia !== '') {
                if (filter !== '') {
                    filter += `&fap:like=${this.currentFamilia}`;
                } else {
                    filter += `fap:like=${this.currentFamilia}`;
                }
            }

            return filter;
        },

        async loadMarcas() {
            try {
                const r = await fetch(url('/isiWeb/web/v1/empresas/01/marcas'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                });

                if (!r.ok) {
                    throw new Error('Error al cargar marcas');
                }

                const response = await r.json();

                this.marcas = response.data as Marca[];
            } catch (error: any) {
                console.log('error', error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
        },

        async loadFamilias() {
            try {
                const r = await fetch(url('/isiWeb/web/v1/empresas/01/familias'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                });

                if (!r.ok) {
                    throw new Error('Error al cargar familias');
                }

                const response = await r.json();

                this.familias = response.data as Familia[];
            } catch (error: any) {
                console.log('error', error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
        },

        async buildReference(e: Event) {
            const reference = (e.target as HTMLInputElement).value;

            try {
                if (reference !== '') {
                    const [referenceData, priceAndDiscount, ivas] = await Promise.all([
                        this.getReferenceData(reference),
                        this.getPriceAndDiscount(reference),
                        this.getIvas(reference),
                    ]);

                    if (!referenceData) {
                        this.$dispatch(REFERENCE_NOT_FOUND, { reference, origin: this.origin as ReferenceOrigin });
                        return;
                    }

                    this.$dispatch(REFERENCE_FOUND, {
                        referenceData,
                        priceAndDiscount,
                        ivas,
                        origin: this.origin as ReferenceOrigin,
                    });
                }
            } catch (error: any) {
                console.log('error', error);
            }
        },

        async getReferenceData(reference: string) {
            try {
                const r = await fetch(url(`/isiWeb/web/v1/empresas/01/referencias/${reference}`), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                });

                if (!r.ok) {
                    throw new Error(r.status.toString());
                }

                const referenceData = await r.json();

                return referenceData as Referencia;
            } catch (error: any) {
                console.log('error', error);
                if (Number.parseInt(error.message) !== 404) {
                    this.$dispatch(TOAST_TRIGGER, { msg: 'Error al cargar datos de referencia', level: ToastError });
                }
            }
        },

        async getPriceAndDiscount(reference: string) {
            try {
                const r = await fetch(url(`/isiWeb/web/v1/empresas/01/referencias/${reference}/precio`), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                });

                if (!r.ok) {
                    throw new Error(r.status.toString());
                }

                const response = await r.json();

                return response as Precio;
            } catch (error: any) {
                console.log('error', error);
                if (Number.parseInt(error.message) !== 404) {
                    this.$dispatch(TOAST_TRIGGER, { msg: 'Error al cargar datos de precios', level: ToastError });
                }
            }
        },

        async getIvas(reference: string) {
            try {
                const r = await fetch(url(`/isiWeb/web/v1/empresas/01/referencias/${reference}/iva`), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                });

                if (!r.ok) {
                    throw new Error(r.status.toString());
                }

                const response = await r.json();

                return response as Iva;
            } catch (error: any) {
                console.log('error', error);
                if (Number.parseInt(error.message) !== 404) {
                    this.$dispatch(TOAST_TRIGGER, { msg: 'Error al cargar datos de IVA', level: ToastError });
                }
            }
        },
    }),
} as ComponentModule;
